		return uc_max;
#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */


#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */

	return uc_req;
