	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */

	WARN_ON_ONCE(!cpu_online(new_cpu));
#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */


#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */

	WARN_ON_ONCE(is_migration_disabled(p));
