#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */

	__balance_callbacks(rq, &rf);
#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */

	__task_rq_unlock(rq, p, &rf);
