#endif /* CONFIG_SCHED_BORE */

	spin_lock_irqsave(&task_group_lock, flags);
#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */

	list_add_tail_rcu(&tg->list, &task_groups);
#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */


#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */

	/* Root should already exist: */
#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */

	WARN_ON(!parent);
#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */


#ifdef CONFIG_SCHED_BORE
	sched_init_bore();
#endif /* CONFIG_SCHED_BORE */

	tg->parent = parent;
